    }

    if((c->avctx->me_sub_cmp&FF_CMP_CHROMA) && !s->dsp.me_sub_cmp[2]){

        s->dsp.me_sub_cmp[2]= zero_cmp;

    }

    c->hpel_put[2][0]= c->hpel_put[2][1]=

    c->hpel_put[2][2]= c->hpel_put[2][3]= zero_hpel;



    c->temp= c->scratchpad;

}

